```class Solution {
public:
    vector<vector<int>> largeGroupPositions(string s) {
        vector<vector<int>> res;
        int start = 0, count = 1;
        for (int i = 1; i < s.size(); i++) {
            if (s[i] == s[i - 1]) {
                count++;
            } else {
                if (count >= 3) {
                    res.push_back({start, i - 1});
                }
                start = i;
                count = 1;
            }
        }
        if (count >= 3) {
            res.push_back({start, s.size() - 1});
        }
        return res;
    }
};
```
